searchData={"items":[{"type":"module","title":"CoffeeTrove","doc":"Access 440K+ cafes, brewing guides, and coffee data from CoffeeTrove.\n\nHomepage: https://coffeetrove.com","ref":"CoffeeTrove.html"},{"type":"function","title":"CoffeeTrove.base_url/0","doc":"","ref":"CoffeeTrove.html#base_url/0"},{"type":"function","title":"CoffeeTrove.version/0","doc":"","ref":"CoffeeTrove.html#version/0"},{"type":"extras","title":"CoffeeTrove Elixir Client","doc":"# CoffeeTrove Elixir Client\n\nElixir client for the [CoffeeTrove](https://coffeetrove.com) coffee data API. Access 440K+ cafes, brewing guides, and coffee data.","ref":"readme.html"},{"type":"extras","title":"Installation - CoffeeTrove Elixir Client","doc":"Add `coffeetrove` to your list of dependencies in `mix.exs`:\n\n```elixir\ndef deps do\n  [\n    {:coffeetrove, \"~> 0.1.0\"}\n  ]\nend\n```","ref":"readme.html#installation"},{"type":"extras","title":"Usage - CoffeeTrove Elixir Client","doc":"```elixir\nCoffeeTrove.version()\n# => \"0.1.0\"\n\nCoffeeTrove.base_url()\n# => \"https://coffeetrove.com\"\n```","ref":"readme.html#usage"},{"type":"extras","title":"Links - CoffeeTrove Elixir Client","doc":"- [Homepage](https://coffeetrove.com)\n- [Documentation](https://coffeetrove.com/knowledge)\n- [GitHub](https://github.com/arnaudleroy-studio/coffeetrove-elixir)","ref":"readme.html#links"},{"type":"extras","title":"License - CoffeeTrove Elixir Client","doc":"MIT License. See [LICENSE](LICENSE) for details.","ref":"readme.html#license"}],"proglang":"elixir","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.40.1"}}